import{_ as a,o as t,c as n,j as r,a as s,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"铁甲雄兵能力组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/铁甲雄兵能力组.md","filePath":"4.资源分区/6.技艺及称号/武技类/铁甲雄兵能力组.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/铁甲雄兵能力组.md"};function d(_,e,b,l,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"铁甲雄兵能力组",tabindex:"-1"},[s("铁甲雄兵能力组 "),r("a",{class:"header-anchor",href:"#铁甲雄兵能力组","aria-label":'Permalink to "铁甲雄兵能力组"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序008")])])],-1),p('<h1 id="铁甲雄兵能力组-1" tabindex="-1">铁甲雄兵能力组 <a class="header-anchor" href="#铁甲雄兵能力组-1" aria-label="Permalink to &quot;铁甲雄兵能力组&quot;">​</a></h1><p>铁甲雄兵能力组<br> 铁甲雄兵是一款……的竞技策略网游，中间省略的不重要，毕竟没给广告费。通过学习本页技艺，就能使用游戏《铁甲雄兵》中武将的力量。持续随缘更新，欢迎各位参与制作（发出鸽子的声音.jpg）</p><p>拒马<br> D+500<br> 架起长柄武器来迎击敌人，这是许多长柄武器士兵都有的技能，是一种克制骑兵的防御方式。实战中，由于架起武器后士兵的攻击方向大约在头部高度，在与步兵对战时也有一定作用。<br> 使用迅捷动作架起长枪来迎击敌人，这视为本轮在你的触及范围内制造了D级困难地形。此外，本轮你对未骑乘载具的敌人进行特定部位攻击时，可以忽略力量上附加成功的特定部位减值，在对骑乘轻型载具的敌人进行特定部位攻击时，获得1附加成功。进行拒马时，你的移动速度下降10M（但可以选择在移动后使用拒马）</p><p>桓侯之力<br> D+500<br> 张飞的被动技能，力大无穷的张飞能用蛇矛一次攻击两人。<br> 在使用长枪类武器时，你的近战攻击视为具有贯穿属性，这表现为你刺穿了前一人的身躯攻击了后者。此外，你获得等同于力量附加成功+1的【破甲】</p><p>拖刀<br> C+1000<br> 关羽的技能，在骑乘中将大刀横立，掠过敌人的同时一刀将其斩杀。<br> 在骑乘轻型载具，使用长柄类可以造成挥砍伤害的武器时才能使用。使用一个自由动作将武器横立，本回合一次，可以将使用该武器进行的一次近战攻击结合在移动中，并额外获得力量上附加成功*2的速度加值。</p><p>圣者祈祷/天佑法兰西<br> C+1500<br> 铁甲雄兵看板娘（？）贞德的技能，在游戏中能为友军提供防御与回血效果。<br> 使用者以移动动作向天空举起武器（没有武器则举起拳头），鼓舞周围的战士，令周围7M范围内的友军（含自己）获得1点快速医疗（医疗点数12），并令友军获得等同于 使用者耐力上的附加成功*1的防御上的士气加值，这个效果持续一场战斗。</p><p>挑衅/看到了吗？我们的敌人是群懦夫！<br> C+1000<br> 理查一世的技能，在游戏中能让敌方士兵进入攻击状态，从而达到破解阵型的效果。<br> 使用者以一个迅捷动作大喝一声：“看到了吗？我们的敌人是群懦夫！”来挑衅前方半径为技能：武技*1M范围扇形区域内的敌人，你使用力量+武技+专业：大喝进行检定，对方使用意志豁免进行对抗，若对方对抗失败，你令其在当前战斗中以你为优先攻击目标，这是一个C级胁迫效果。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
